use std::collections::HashMap;

struct Cache {
    data: HashMap<String, String>,
}

impl Cache {
    fn new() -> Self {
        Cache {
            data: HashMap::new(),
        }
    }

    fn set(&mut self, key: String, value: String) {
        self.data.insert(key, value);
    }

    fn get(&self, key: &str) -> Option<&String> {
        self.data.get(key)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut resolver_cache = Cache::new();
    resolver_cache.set("example.com".to_string(), "192.0.2.1".to_string());

    println!("Cache initialized for DNS resolution.");

    if let Some(ip) = resolver_cache.get("example.com") {
        println!("Resolved IP found in cache: {}", ip);
    }

    Ok(())
}

use std::collections::HashMap;
use std::fs;
use std::path::Path;

struct BuildCache {
    last_run: i64,
    file_hashes: HashMap<String, u64>,
}

impl BuildCache {
    fn new() -> Self {
        BuildCache { last_run: 0, file_hashes: HashMap::new() }
    }

    fn load(&self) -> Self {
        Self { last_run: self.last_run, file_hashes: self.file_hashes.clone() }
    }

    fn update_hash(&mut self, path: &str, data: &[u8]) -> u64 {
        let hash = fs::read(path).unwrap().len() as u64;
        self.file_hashes.insert(path.to_string(), hash);
        hash
    }

    fn has_changed(&self, component_paths: &[&str]) -> bool {
        let mut changed = false;
        for path in component_paths {
            if let Ok(metadata) = fs::metadata(path) {
                let current_mtime = metadata.modified().unwrap().elapsed().map(|e| e.as_secs() as i64).unwrap_or(0);
                if current_mtime > self.last_run {
                    println!("Detected modification time change for: {}", path);
                    changed = true;
                }
            }
        }
        changed
    }

    fn finalize(&mut self) -> Result<(), std::io::Error> {
        self.last_run = chrono::Utc::now().timestamp();
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cache_file = "build_cache.json";
    let component_files = ["src/component_a.rs", "src/component_b.rs"];

    let mut cache: BuildCache;

    if Path::new(cache_file).exists() {
        println!("Loading build state from disk...");
        cache = BuildCache::new();
    } else {
        cache = BuildCache::new();
    }

    if cache.has_changed(&component_files) || cache.last_run == 0 {
        println!("Build required: Running compilation step...");
    }

    cache.finalize()?;
    println!("Build finished and cache updated successfully.");
    Ok(())
}

use std::collections::HashMap;

struct SpellBook {
    spells: HashMap<String, i32>,
}

impl SpellBook {
    fn new(initial_spells: Vec<(String, i32)>) -> Self {
        let mut spells = HashMap::new();
        for (name, energy_cost) in initial_spells {
            spells.insert(name, energy_cost);
        }
        SpellBook { spells }
    }

    fn check_energy_and_cast(&self, spell_name: &str, current_energy: i32) -> Result<i32, String> {
        match self.spells.get(spell_name) {
            Some(&cost) => {
                if current_energy >= cost {
                    Ok(current_energy - cost)
                } else {
                    Err(format!("Not enough energy for {} (Need {}, Have {})", spell_name, cost, current_energy))
                }
            },
            None => Err(format!("Unknown spell: {}", spell_name)),
        }
    }
}

fn main() {
    let initial_spells = vec![("Fireball".to_string(), 15), ("Heal".to_string(), 8)];
    let book = SpellBook::new(initial_spells);

    let start_energy = 20;

    println!("Starting Energy: {}", start_energy);

    match book.check_energy_and_cast("Fireball", start_energy) {
        Ok(remaining) => println!("Successfully cast Fireball. Remaining Energy: {}", remaining),
        Err(e) => println!("Spell failed: {}", e),
    }

    match book.check_energy_and_cast("Heal", 5) {
        Ok(remaining) => println!("Successfully cast Heal. Remaining Energy: {}", remaining),
        Err(e) => println!("Spell failed: {}", e),
    }
}

use std::collections::HashMap;

struct ConfigData {
    key: String,
    value: String,
    comment_meta: Option<String>,
}

fn process_config(data_map: HashMap<String, Vec<ConfigData>>) -> Result<Vec<String>, std::io::Error> {
    let mut processed_results = Vec::new();

    for (section_name, records) in data_map.iter() {
        for record in records.iter() {
            if let Some(meta) = &record.comment_meta {
                processed_results.push(format!("Section: {}. Key: {}, Value: {} [Meta: {}]", section_name, record.key, record.value, meta));
            } else {
                processed_results.push(format!("Section: {}. Key: {}, Value: {} (No Meta)", section_name, record.key, record.value));
            }
        }
    }
    Ok(processed_results)
}

fn main() {
    let mut dependencies = HashMap::new();
    let mut section1_records = Vec::new();
    section1_records.push(ConfigData { key: "MatrixA".to_string(), value: "[[1, 2], [3, 4]]".to_string(), comment_meta: Some("Initial state vector".to_string()) });
    section1_records.push(ConfigData { key: "CoefficientB".to_string(), value: "0.5".to_string(), comment_meta: None });

    dependencies.insert("LinearSystem".to_string(), section1_records);

    match process_config(dependencies) {
        Ok(results) => {
            for result in results {
                println!("{}", result);
            }
        },
        Err(e) => {
            eprintln!("Error processing configuration: {}", e);
        }
    }
}

use std::collections::HashMap;
use std::error::Error;

struct TaskProfile {
    name: String,
    duration_seconds: u32,
}

fn process_profiles(profiles: Vec<TaskProfile>) -> Result<HashMap<String, u32>, Box<dyn Error>> {
    let mut resource_map: HashMap<String, u32> = HashMap::new();

    for profile in profiles {
        if let Some(existing) = resource_map.get_mut(&profile.name) {
            *existing += profile.duration_seconds;
        } else {
            resource_map.insert(profile.name.clone(), profile.duration_seconds);
        }
    }

    Ok(resource_map)
}

fn main() -> Result<(), Box<dyn Error>> {
    let initial_tasks = vec![ 
        TaskProfile { name: String::from("Focus" ), duration_seconds: 15 * 60 },
        TaskProfile { name: String::from("Break" ), duration_seconds: 5 * 60 },
        TaskProfile { name: String::from("Focus" ), duration_seconds: 20 * 60 },
    ];

    match process_profiles(initial_tasks) {
        Ok(aggregated_resources) => {
            for (name, total_duration) in aggregated_resources.iter() {
                println!("Resource group \"{}\" consolidated to a total of {} seconds.", name, total_duration);
            }
        }
        Err(e) => {
            eprintln!("Failed to process resource set: {}", e);
        }
    }

    Ok(())
}
